    if not USE_LR_SCHEDULE:
        return None
    total_steps = TRAIN_MAX_STEPS if TRAIN_MAX_STEPS is not None else steps_per_epoch * 100
    warmup_steps = max(1, min(total_steps // 4, WARMUP_EPOCHS * steps_per_epoch))

    def lr_lambda(step_idx: int) -> float:
        if step_idx < warmup_steps:
            return float(step_idx + 1) / float(warmup_steps)
        decay_steps = max(1, total_steps - warmup_steps)
        progress = (step_idx - warmup_steps) / float(decay_steps)
        return float(0.5 * (1.0 + torch.cos(torch.tensor(torch.pi * progress)).item()))

    return optim.lr_scheduler.LambdaLR(optimizer, lr_lambda)
